        self.histogram[coord] += weight
    else:
        self.histogram[coord] = weight

import re

class ValidationError(Exception):
    def __init__(self, messages):
        self.messages = messages

def _validate_labels(labels):
    errors = []
    key_regex = r'^[a-zA-Z_][a-zA-Z0-9_]*$'  # Example regex for keys
    value_regex = r'^[a-zA-Z0-9_]+$'  # Example regex for values

    for key, value in labels.items():
        if not isinstance(key, str) or not re.match(key_regex, key):
            errors.append({key: f"Label key '{key}' does not match the regex [{key_regex}]"})

        if isinstance(value, str):
            if not re.match(value_regex, value):
                errors.append({value: 'expected string or bytes-like object'})
        else:
            errors.append({str(value): 'expected string or bytes-like object'})

    if errors:
        raise ValidationError(errors)

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    new_dict = {}

    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            new_dict[key] = generate_default_observer_schema_dict(value, first_level=False)
        elif isinstance(value, list):
            new_dict[key] = [generate_default_observer_schema_dict(item, first_level=False) if isinstance(item, dict) else None for item in value]
        else:
            if first_level and key in ['kind', 'apiVersion', 'metadata']:
                new_dict[key] = value
            else:
                new_dict[key] = None

    return new_dict

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Insieme alla funzione :func:``update_last_applied_manifest_list_from_resp``, 
    questa funzione viene chiamata ricorsivamente per aggiornare un 
    ``last_applied_manifest`` parziale a partire da una risposta parziale di Kubernetes.

    Argomenti:
        last_applied_manifest (dict): ``last_applied_manifest`` parziale in fase di aggiornamento
        observer_schema (dict): ``observer_schema`` parziale
        response (dict): risposta parziale dall'API di Kubernetes.

    Eccezioni:
        KeyError: Se il campo osservato non è presente nella risposta di Kubernetes.

    Questa funzione analizza tutti i campi osservati e inizializza il loro valore 
    in ``last_applied_manifest`` se non sono ancora presenti.
    """
    for key, value in observer_schema.items():
        if isinstance(value, dict):
            # Recursive call for nested dictionaries
            if key not in last_applied_manifest:
                last_applied_manifest[key] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[key], value, response.get(key, {})
            )
        else:
            # Check if the key is in the response and update last_applied_manifest
            if key not in last_applied_manifest:
                if key not in response:
                    raise KeyError(f"Field '{key}' is not present in the Kubernetes response.")
                last_applied_manifest[key] = response[key]

def generate_default_observer_schema(app):
    """
    Genera lo schema di osservazione predefinito per ogni risorsa Kubernetes presente in
    ``spec.manifest`` per la quale non è stato specificato uno schema di osservazione personalizzato.

    Argomenti:
        app (krake.data.kubernetes.Application): L'applicazione per la quale generare uno
            schema di osservazione predefinito.
    """
    default_schema = {}
    for resource in app.spec.manifest:
        resource_type = resource.get('kind')
        if resource_type not in default_schema:
            default_schema[resource_type] = {
                'apiVersion': resource.get('apiVersion'),
                'metadata': {
                    'name': resource.get('metadata', {}).get('name'),
                    'namespace': resource.get('metadata', {}).get('namespace'),
                },
                'spec': resource.get('spec', {})
            }
    return default_schema

from typing import AnyStr, Union, Dict, Sequence, Tuple

def format(
                self,
                sql: AnyStr,
                params: Union[Dict[Union[str, int], Any], Sequence[Any]],
        ) -> Tuple[AnyStr, Union[Dict[Union[str, int], Any], Sequence[Any]]]:
    """
    Converte la query SQL per utilizzare i parametri in stile "out" invece dei parametri in stile "in".

    **sql** (:class:`str` o :class:`bytes`) è la query SQL.

    Restituisce una :class:`tuple` contenente:

    - La query SQL formattata (:class:`str` o :class:`bytes`).

    - L'insieme dei parametri convertiti in stile "out" (:class:`dict` o :class:`list`).
    """
    # Example implementation (this should be replaced with actual logic)
    if isinstance(sql, bytes):
        formatted_sql = sql.decode('utf-8')
    else:
        formatted_sql = sql

    if isinstance(params, dict):
        out_params = {key: f'OUT_{value}' for key, value in params.items()}
    else:
        out_params = [f'OUT_{value}' for value in params]

    return formatted_sql, out_params

def formatmany(
                self,
                sql: AnyStr,
                many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
        ) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:
    # Convert the SQL query to use "out" style parameters
    out_params = []
    param_count = 0

    # Determine the parameter style
    if isinstance(many_params, dict):
        for params in many_params:
            if isinstance(params, dict):
                out_params.append({k: v for k, v in params.items()})
                param_count += len(params)
            elif isinstance(params, (list, tuple)):
                out_params.append(list(params))
                param_count += len(params)
    else:
        for params in many_params:
            if isinstance(params, dict):
                out_params.append({k: v for k, v in params.items()})
                param_count += len(params)
            elif isinstance(params, (list, tuple)):
                out_params.append(list(params))
                param_count += len(params)

    # Format the SQL query to replace "in" style with "out" style
    formatted_sql = sql.replace("IN (", "OUT (").replace("?", "%s")  # Example replacement logic

    return formatted_sql, out_params

def validate(self, inventory, extract_spec_version=False):
    """
    Convalida un inventario specificato.

    Se `extract_spec_version` è impostato su `True`, verrà esaminato il valore del tipo (`type`) 
    per determinare la versione della specifica. Nel caso in cui non sia presente un valore per 
    il tipo o questo non sia valido, verranno eseguiti altri test basati sulla versione specificata 
    in `self.spec_version`.
    """
    if extract_spec_version:
        if 'type' in inventory and inventory['type'] in self.valid_types:
            self.spec_version = inventory['type']
        else:
            self.spec_version = self.default_spec_version

    # Esegui la convalida dell'inventario in base alla versione della specifica
    if self.spec_version == '1.0':
        return self.validate_v1(inventory)
    elif self.spec_version == '2.0':
        return self.validate_v2(inventory)
    else:
        raise ValueError("Versione della specifica non valida.")

