    for bug_id in bug_ids:
        if bug_id in params:
            params[bug_id]['status'] = 'modified'
            # Add any additional modifications needed for Bugzilla parameters
    return params

from ruamel.yaml.nodes import ScalarNode, MappingNode

def deep_merge_nodes(nodes):
    """
    Dato una struttura configuratione di struttura data annidata di borgmatic sotto forma di una lista di tuple nel formato:

        (
            ruamel.yaml.nodes.ScalarNode come chiave,
            ruamel.yaml.nodes.MappingNode o un altro tipo di Node come valore,
        ),

    ... esegui una fusione profonda (deep merge) dei valori dei nodi corrispondenti a chiavi duplicate e restituisci il risultato. Se ci sono chiavi in conflitto con valori non di tipo `MappingNode` (ad esempio, interi o stringhe), l'ultimo dei valori prevale.

    Ad esempio, dati i seguenti valori dei nodi:

        [
            (
                ScalarNode(tag='tag:yaml.org,2002:str', value='retention'),
                MappingNode(tag='tag:yaml.org,2002:map', value=[
                    (
                        ScalarNode(tag='tag:yaml.org,2002:str', value='keep_hourly'),
                        ScalarNode(tag='tag:yaml.org,2002:int', value='24')
                    ),
                    (
                        ScalarNode(tag='tag:yaml.org,2002:str', value='keep_daily'),
                        ScalarNode(tag='tag:yaml.org,2002:int', value='7')
                    ),
                ]),
            ),
            (
                ScalarNode(tag='tag:yaml.org,2002:str', value='retention'),
                MappingNode(tag='tag:yaml.org,2002:map', value=[
                    (
                        ScalarNode(tag='tag:yaml.org,2002:str', value='keep_daily'),
                        ScalarNode(tag='tag:yaml.org,2002:int', value='5')
                    ),
                ]),
            ),
        ]

    ... il risultato restituito sarebbe:

        [
            (
                ScalarNode(tag='tag:yaml.org,2002:str', value='retention'),
                MappingNode(tag='tag:yaml.org,2002:map', value=[
                    (
                        ScalarNode(tag='tag:yaml.org,2002:str', value='keep_hourly'),
                        ScalarNode(tag='tag:yaml.org,2002:int', value='24')
                    ),
                    (
                        ScalarNode(tag='tag:yaml.org,2002:str', value='keep_daily'),
                        ScalarNode(tag='tag:yaml.org,2002:int', value='5')
                    ),
                ]),
            ),
        ]

    Lo scopo di una fusione profonda come questa è supportare, ad esempio, la fusione di un file di configurazione borgmatic in un altro per il riutilizzo, in modo che una sezione di configurazione ("retention", ecc.) non sostituisca completamente la sezione corrispondente in un file unito.
    """
    merged = {}

    for key_node, value_node in nodes:
        key = key_node.value
        if key not in merged:
            merged[key] = value_node
        else:
            if isinstance(merged[key], MappingNode) and isinstance(value_node, MappingNode):
                # Deep merge the mapping nodes
                for sub_key_node, sub_value_node in value_node.value:
                    merged_value = merged[key].value
                    merged_value_dict = {k.value: v for k, v in merged_value}
                    merged_value_dict[sub_key_node.value] = sub_value_node
                    merged[key] = MappingNode(tag='tag:yaml.org,2002:map', value=[
                        (ScalarNode(tag='tag:yaml.org,2002:str', value=k), v) for k, v in merged_value_dict.items()
                    ])
            else:
                # If there's a conflict, take the last value
                merged[key] = value_node

    return [(ScalarNode(tag='tag:yaml.org,2002:str', value=k), v) for k, v in merged.items()]

def parser_flags(parser):
    """
    Dato un'istanza di argparse.ArgumentParser, restituisce le sue opzioni (flag) 
    degli argomenti in una stringa separata da spazi.
    """
    return ' '.join([action.option_strings[0] for action in parser._actions if action.option_strings])

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dato un insieme di argomenti e un dizionario che associa il nome di un sottoparser a un'istanza di `argparse.ArgumentParser`, consente a ciascun sottoparser richiesto di tentare di analizzare tutti gli argomenti. Questo permette di condividere argomenti comuni, come "--repository", tra più sottoparser.

    Restituisce il risultato come una tupla composta da (un dizionario che associa il nome del sottoparser a uno spazio dei nomi di argomenti analizzati, una lista di argomenti rimanenti non gestiti da alcun sottoparser).
    """
    parsed_results = {}
    remaining_arguments = unparsed_arguments[:]

    for name, parser in subparsers.items():
        try:
            parsed_args, remaining_arguments = parser.parse_known_args(remaining_arguments)
            parsed_results[name] = parsed_args
        except SystemExit:
            continue  # Ignore errors from parsers that cannot parse the arguments

    return parsed_results, remaining_arguments

def deep_merge_nodes(nodes):
    from ruamel.yaml.nodes import ScalarNode, MappingNode

    merged = {}

    for key_node, value_node in nodes:
        key = key_node.value
        if key not in merged:
            merged[key] = value_node
        else:
            existing_value = merged[key]
            if isinstance(existing_value, MappingNode) and isinstance(value_node, MappingNode):
                # Merge the two MappingNodes
                for sub_key_node, sub_value_node in value_node.value:
                    existing_value.value.append((sub_key_node, sub_value_node))
            else:
                # If there's a conflict, take the last value
                merged[key] = value_node

    return [(ScalarNode(tag='tag:yaml.org,2002:str', value=key), value) for key, value in merged.items()]

def parser_flags(parser):
    """
    Dato un'istanza di argparse.ArgumentParser, restituisce i flag degli argomenti
    in una stringa separata da spazi.
    """
    return ' '.join([action.option_strings[0] for action in parser._actions if action.option_strings])

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dato un insieme di argomenti e un dizionario che associa il nome di un sottoparser a un'istanza di `argparse.ArgumentParser`, consente a ciascun sottoparser richiesto di tentare di analizzare tutti gli argomenti. Questo permette di condividere argomenti comuni, come "--repository", tra più sottoparser.

    Restituisce il risultato come una tupla composta da (un dizionario che associa il nome del sottoparser a uno spazio dei nomi analizzato degli argomenti, una lista di argomenti rimanenti non gestiti da alcun sottoparser).
    """
    parsed_results = {}
    remaining_arguments = unparsed_arguments[:]

    for name, parser in subparsers.items():
        try:
            parsed_args, remaining_arguments = parser.parse_known_args(remaining_arguments)
            parsed_results[name] = parsed_args
        except SystemExit:
            continue  # Ignore errors from parsers that cannot parse the arguments

    return parsed_results, remaining_arguments

def _dictsum(dicts):
    """
    Combina i valori dei dizionari forniti tramite l'iterabile `dicts`.

    >>> _dictsum([{'a': 1, 'b': 2}, {'a': 5, 'b': 0}])
    {'a': 6, 'b': 2}
    """
    from collections import defaultdict

    result = defaultdict(int)
    for d in dicts:
        for key, value in d.items():
            result[key] += value

    return dict(result)

def is_none_string(val: any) -> bool:
    """
    Verifica se una stringa rappresenta un valore None.
    """
    return val is None or (isinstance(val, str) and val.lower() == 'none')

from typing import List, Optional

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    if number < 0:
        raise ValueError("Number must be non-negative")

    base = len(alphabet)
    if base < 2:
        raise ValueError("Alphabet must contain at least two characters")

    if number == 0:
        result = alphabet[0]
    else:
        result = ""
        while number > 0:
            result = alphabet[number % base] + result
            number //= base

    if padding is not None:
        result = result.rjust(padding, alphabet[0])

    return result

def replace_dots(value, arg):  
    """
    Sostituisce tutti i valori di '.' con arg nella stringa fornita
    """
    return value.replace('.', arg)

def unquote(name):
    """
    Rimuovi le virgolette dal nome fornito.
    """
    return name.replace('"', '').replace("'", "")

import re

def get_pattern(pattern, strip=True):
    """
    Questo metodo converte la stringa fornita in un oggetto pattern regex
    """
    if strip:
        pattern = pattern.strip()
    return re.compile(pattern)

from typing import Optional, Set
from rdflib import Graph, URIRef

def find_roots(
    graph: Graph, prop: URIRef, roots: Optional[Set["Node"]] = None
) -> Set["Node"]:
    if roots is None:
        roots = set()

    # Get all nodes that have no parents
    all_children = {s for s, p, o in graph.triples((None, prop, None))}
    all_parents = {o for s, p, o in graph.triples((None, prop, None))}

    # Roots are those nodes that are not parents of any other nodes
    roots = all_children - all_parents

    return roots

def _dump_string(obj, dumper=None):
    """
    Serializza in una stringa Unicode (Python 2) o in una stringa (Python 3).
    """
    if isinstance(obj, str):
        return obj
    elif isinstance(obj, bytes):
        return obj.decode('utf-8')
    else:
        raise TypeError("Expected a string or bytes, got {}".format(type(obj)))

import json
import logging
import os

def load_configurations(config_filenames, overrides=None, resolve_env=True):
    """
    Dato un elenco di nomi di file di configurazione, carica e valida ciascun file di configurazione.
    Restituisci i risultati come una tupla composta da:
    - un dizionario che associa il nome del file di configurazione alla corrispondente configurazione analizzata,
    - una sequenza di istanze di `logging.LogRecord` contenenti eventuali errori di analisi.
    """
    if overrides is None:
        overrides = {}

    configurations = {}
    log_records = []
    logger = logging.getLogger(__name__)

    for filename in config_filenames:
        try:
            with open(filename, 'r') as f:
                config = json.load(f)
                if resolve_env:
                    config = {k: os.path.expandvars(v) for k, v in config.items()}
                configurations[filename] = {**config, **overrides}
        except Exception as e:
            log_record = logger.error(f"Error loading configuration from {filename}: {e}")
            log_records.append(log_record)

    return configurations, log_records

def force_string(obj):
    """
    Questa funzione restituisce l'oggetto di tipo `bytes` corrispondente a ``obj`` nel caso in cui sia una stringa utilizzando UTF-8.
    """
    if isinstance(obj, str):
        return obj.encode('utf-8')
    return obj

def _get_seq_with_type(seq, bufsize=None):
    """
    Restituisce una coppia (sequenza, tipo).  
    La sequenza è derivata da *seq*  
    (oppure è *seq*, se quest'ultima è di un tipo sequenza).
    """
    if isinstance(seq, (list, tuple, set, str)):
        return seq, type(seq)
    else:
        if bufsize is not None:
            seq = list(seq)[:bufsize]
        else:
            seq = list(seq)
        return seq, type(seq)

def scale(self, other=None, recompute=False):
    """
    Calcola o imposta la scala (integrale dell'istogramma).

    Se *other* è ``None``, restituisce la scala di questo istogramma.  
    Se la scala non è stata calcolata in precedenza, viene calcolata e memorizzata per un utilizzo successivo (a meno che non venga esplicitamente richiesto di *ricalcolare*).  
    Nota che, dopo aver modificato (riempito) l'istogramma, è necessario ricalcolare esplicitamente la scala se era stata calcolata in precedenza.

    Se viene fornito un valore float in *other*, l'oggetto corrente (*self*) viene riscalato al valore di *other*.

    Gli istogrammi con scala pari a zero non possono essere riscalati.  
    Viene sollevata un'eccezione :exc:`.LenaValueError` se si tenta di farlo.
    """
    if other is None:
        if not hasattr(self, '_scale') or recompute:
            self._scale = self._calculate_scale()
        return self._scale

    if isinstance(other, float):
        if self._scale == 0:
            raise LenaValueError("Cannot rescale histogram with zero scale.")
        self._rescale(other)
    else:
        raise TypeError("Expected a float value for 'other'.")

def verifyClass(iface, candidate, tentative=False):
    """
    Verifica che il *candidate* possa fornire correttamente *iface*.
    """
    if tentative:
        return issubclass(candidate, iface) or iface in candidate.__bases__
    return issubclass(candidate, iface)

def determineMetaclass(bases, explicit_mc=None):
    """
    Determina la metaclasse a partire da una o più basi e da un'eventuale __metaclass__ esplicita.
    """
    if explicit_mc is not None:
        return explicit_mc

    metaclasses = [type(base) for base in bases]
    if not metaclasses:
        return type

    # Find the common metaclass
    common_metaclass = metaclasses[0]
    for mc in metaclasses[1:]:
        if not issubclass(mc, common_metaclass):
            common_metaclass = type('Meta', (common_metaclass, mc), {})

    return common_metaclass

def pop(self, key, default=__marker):
    """
    D.pop(k[,d]) -> v, rimuove la chiave specificata e restituisce il valore corrispondente.  
    Se la chiave non viene trovata, viene restituito `d` se fornito, altrimenti viene sollevata un'eccezione KeyError.
    """
    if key in self:
        value = self[key]
        del self[key]
        return value
    elif default is not self.__marker:
        return default
    else:
        raise KeyError(f"Key {key} not found.")

def _create_converter(self) -> _converting._Converter:
    """
    Crea il convertitore dello stile dei parametri.

    Restituisce il convertitore dello stile dei parametri (:class:`._converting._Converter`).
    """
    return _converting._Converter()

def fromutc(self, dt):
    """
    Dato un oggetto datetime con consapevolezza del fuso orario (timezone-aware) in un determinato fuso orario, calcola un oggetto datetime con consapevolezza del fuso orario in un nuovo fuso orario.

    Poiché questa è l'unica occasione in cui *sappiamo* di avere un oggetto datetime non ambiguo, cogliamo l'opportunità per determinare se il datetime è ambiguo e si trova in uno stato di "fold" (ad esempio, se è la prima occorrenza, in ordine cronologico, del datetime ambiguo).

    :param dt:  
        Un oggetto :class:`datetime.datetime` con consapevolezza del fuso orario (timezone-aware).
    """
    if dt.tzinfo is None:
        raise ValueError("dt must be timezone-aware")

    # Convert the datetime to UTC
    utc_dt = dt.astimezone(self.utc)

    # Check if the datetime is ambiguous
    if self._is_ambiguous(utc_dt):
        # Handle the ambiguity (e.g., by checking if it's in the fold)
        if self._is_in_fold(utc_dt):
            return utc_dt.replace(fold=1)
        else:
            return utc_dt.replace(fold=0)

    # Return the converted datetime in the new timezone
    return utc_dt.astimezone(self)

def identify_request(request: RequestType):
    """
    Prova a identificare se si tratta di una richiesta Diaspora.

    Prova prima con un messaggio pubblico. Poi con un messaggio privato. Infine, verifica se si tratta di un payload legacy.
    """
    if request.is_public_message():
        return "Public message identified"
    elif request.is_private_message():
        return "Private message identified"
    elif request.is_legacy_payload():
        return "Legacy payload identified"
    else:
        return "Unknown request type"

def identify_request(request: RequestType) -> bool:
    """
    Prova a identificare se si tratta di una richiesta Matrix.
    """
    return isinstance(request, MatrixRequestType)

