def validate_arg_deprecation(self, cli_args, answer_file_args):
    """
    Valida e stampa gli argomenti deprecati.

    :param cli_args: il dizionario degli argomenti dalla CLI
    :param answer_file_args: il dizionario degli argomenti dai file
    """
    deprecated_args = set(cli_args.keys()).intersection(set(answer_file_args.keys()))

    if deprecated_args:
        print("Attenzione: gli argomenti seguenti sono deprecati:")
        for arg in deprecated_args:
            print(f"- {arg}")
    else:
        print("Nessun argomento deprecato trovato.")

def get_parser_option_specs(self, command_name):
    """
    Ottiene tutte le opzioni per il comando specificato

    :param command_name: il nome del comando (main, virsh, ospd, ecc...)
    :return: la lista di tutte le opzioni del comando
    """
    options = {
        'main': ['--help', '--version', '--verbose'],
        'virsh': ['--connect', '--list', '--start', '--shutdown'],
        'ospd': ['--config', '--debug', '--status'],
    }

    return options.get(command_name, [])

def get_option_spec(self, command_name, argument_name):
    """
    Ottiene la specifica per il nome dell'opzione specificato.
    """
    # Assuming there's a dictionary that holds command options
    command_options = {
        'command1': {'arg1': 'spec1', 'arg2': 'spec2'},
        'command2': {'arg1': 'spec3', 'arg2': 'spec4'},
    }

    if command_name in command_options:
        if argument_name in command_options[command_name]:
            return command_options[command_name][argument_name]
        else:
            return f"Argument '{argument_name}' not found for command '{command_name}'."
    else:
        return f"Command '{command_name}' not found."

def validate_length_args(self, args):  
    """
    Verifica se il valore degli argomenti non supera la lunghezza specificata.  

    :param args: Gli argomenti ricevuti.  
    """
    max_length = 100  # Imposta la lunghezza massima consentita
    for arg in args:
        if len(arg) > max_length:
            raise ValueError(f"L'argomento '{arg}' supera la lunghezza massima di {max_length}.")
    return True

def validate_choices_args(self, args):  
    """
    Verifica se il valore degli argomenti di scelta è una delle opzioni disponibili.  

    :param args: Gli argomenti ricevuti.  
    """
    available_choices = self.get_available_choices()  # Assuming this method exists
    for arg in args:
        if arg not in available_choices:
            raise ValueError(f"'{arg}' non è una scelta valida. Scelte disponibili: {available_choices}")

def validate_min_max_args(self, args):
    """
    Verifica se il valore degli argomenti è compreso tra i valori minimo e massimo.

    :param args: Gli argomenti ricevuti.
    """
    min_value = self.min_value  # Assuming min_value is defined in the class
    max_value = self.max_value  # Assuming max_value is defined in the class

    for arg in args:
        if not (min_value <= arg <= max_value):
            raise ValueError(f"Il valore {arg} non è compreso tra {min_value} e {max_value}.")

def get_nested_custom_and_control_args(self, args):
    """
    Suddivide gli argomenti di input in controlli nidificati e personalizzati.

    Argomenti di controllo: controllano il comportamento dell'IR. Questi argomenti
        non saranno inseriti nel file spec yml.
    Argomenti nidificati: sono utilizzati dai playbook di Ansible e saranno inseriti
        nel file spec yml.
    Argomenti personalizzati: variabili Ansible personalizzate da utilizzare al posto
        dell'uso normale degli argomenti nidificati.

    :param args: la lista raccolta di argomenti.
    :return: (dict, dict): dizionari piatti (control_args, nested_args)
    """
    control_args = {}
    nested_args = {}

    for arg in args:
        if isinstance(arg, dict):
            for key, value in arg.items():
                if key.startswith('control_'):
                    control_args[key] = value
                elif key.startswith('nested_'):
                    nested_args[key] = value
                else:
                    nested_args[key] = value  # Treat as custom if not prefixed
        else:
            # Handle non-dict args if necessary
            pass

    return control_args, nested_args

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    Estende ``vars_dict`` con ``extra-vars``

    :param vars_dict: Dizionario in cui unire le extra-vars
    :param extra_vars: Lista di extra-vars
    """
    if extra_vars is None:
        return vars_dict

    for var in extra_vars:
        if isinstance(var, dict):
            vars_dict.update(var)
        else:
            raise ValueError("Each extra var must be a dictionary.")

    return vars_dict

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    Converte gli argomenti nei tipi corretti modificando il parametro values_dict.

    Per impostazione predefinita, tutti i valori sono stringhe.

    :param parser_name: Il nome del comando, ad esempio main, virsh, ospd, ecc.
    :param values_dict: Il dizionario con gli argomenti
    """
    for key, value in values_dict.items():
        if value.isdigit():
            values_dict[key] = int(value)
        else:
            try:
                # Attempt to convert to float if it's not an integer
                values_dict[key] = float(value)
            except ValueError:
                # Keep it as a string if conversion fails
                values_dict[key] = value

import os
import json

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    Crea un dizionario non annidato a partire dalle specifiche del plugin.

    :param plugin_dir: Un percorso alla directory del plugin  
    :return: Un dizionario piatto che contiene le proprietà del plugin
    """
    flatten_dict = {}

    # Assuming there is a 'spec.json' file in the plugin directory
    spec_file_path = os.path.join(plugin_dir, 'spec.json')

    if os.path.exists(spec_file_path):
        with open(spec_file_path, 'r') as spec_file:
            spec_data = json.load(spec_file)
            flatten_dict = flatten(spec_data)

    return flatten_dict

def flatten(d, parent_key='', sep='_'):
    items = []
    for k, v in d.items():
        new_key = f"{parent_key}{sep}{k}" if parent_key else k
        if isinstance(v, dict):
            items.extend(flatten(v, new_key, sep=sep).items())
        else:
            items.append((new_key, v))
    return dict(items)

def strip_root(percorso, radice):
    """
    Rimuovi la radice dal percorso, genera un'eccezione in caso di errore.
    """
    if not isinstance(percorso, str) or not isinstance(radice, str):
        raise ValueError("Entrambi i parametri devono essere stringhe.")

    if percorso.startswith(radice):
        return percorso[len(radice):]
    else:
        raise ValueError("Il percorso non inizia con la radice specificata.")
